INSERT INTO historical_events (date_key, year, title, description, category) VALUES
('01-01', 1879, 'Начало на Учредителното събрание', 'Открито е Учредителното народно събрание в Търново, което приема Търновската конституция.', 'history'),
('01-02', 1831, 'Роден е Васил Левски (по някои източници)', 'Апостолът на свободата - ключова фигура в българското освободително движение.', 'history'),
('01-05', 1919, 'Начало на Парижката мирна конференция', 'След Първата световна война победителите се събират, за да определят условията за мир.', 'world'),
('01-10', 1920, 'Образуване на Обществото на народите', 'Първата международна организация, целяща запазване на мира след Първата световна война.', 'world'),
('01-15', 1929, 'Роден е Мартин Лутър Кинг', 'Американски баптистки свещеник и лидер на движението за граждански права.', 'world'),
('01-20', 1942, 'Ванзе conference', 'Нацистките лидери планират окончателното решение на еврейския въпрос.', 'world'),
('01-27', 1945, 'Освобождението на Аушвиц', 'Съветските войски освобождават концентрационния лагер Аушвиц.', 'world'),
('02-01', 1891, 'Основаване на БРСДП', 'Учредена е Българската работническа социалдемократическа партия.', 'history'),
('02-10', 1947, 'Парижкият мирен договор', 'Подписан е Парижкият мирен договор, с който се слага край на Втората световна война за България.', 'history'),
('02-19', 1878, 'Начало на Санстефанския договор', 'Започват преговорите за мирен договор между Русия и Османската империя.', 'history'),
('03-01', 1870, 'Създаване на Българската екзархия', 'Султанският ферман утвърждава Българската екзархия като самостоятелна църква.', 'history'),
('03-10', 1878, 'Подписан е Санстефанският мирен договор', 'С договора се създава автономна българска държава.', 'history'),
('03-25', 1957, 'Подписан е Римският договор', 'Шест държави подписват договора за създаване на Европейската икономическа общност.', 'world'),
('04-10', 1879, 'Приета е Търновската конституция', 'Първата българска конституция е приета от Учредителното събрание.', 'history'),
('04-25', 2005, 'България подписва договор за членство в ЕС', 'България подписва договора за присъединяване към Европейския съюз.', 'history'),
('05-02', 1876, 'Начало на Априлското въстание', 'Българският народ се вдига на въстание срещу османското владичество.', 'history'),
('05-11', 927, 'Смъртта на цар Симеон Велики', 'Един от най-великите български владетели умира след 34-годишно управление.', 'history'),
