INSERT INTO folk_traditions (date_key, month, title, content, proverb, category) VALUES
('01-06', 1, 'Йордановден - Водосвет', 'На Йордановден свещениците хвърлят кръста в реката, а момци се гмуркат да го извадят. Който го извади първи, ще бъде здрав и благословен през годината.', 'Кръстът в ледената вода носи здраве за цяла година.', 'tradition'),
('01-07', 1, 'Иванден - Мъжки празник', 'На Иванден се празнува в чест на Св. Йоан Кръстител. На този ден не се пере, не се работи за да не се разсърдят мъжете.', 'На Иванден мъжете са царете на деня.', 'tradition'),
('01-14', 1, 'Сурва - Нова година по стар стил', 'По стар стил се чества Нова година. Децата със сурвачки обикалят домовете и пожелават здраве и берекет.', 'Сурва, сурва, година - здраве и берекет!', 'tradition'),
('01-18', 1, 'Атанасовден', 'На Атанасовден се коли черно пиле за здраве. Смята се, че на този ден зимата започва да си отива.', 'На Атанасовден зимата се обръща към лятото.', 'tradition'),
('02-01', 2, 'Трифоновден - Лозарски празник', 'На Трифоновден се празнува в чест на Св. Трифон, покровител на лозарите. Върбата се реже, за да има берекет от лозята.', 'На Трифоновден - в лозята, на Димитровден - в избите.', 'tradition'),
('02-02', 2, 'Гергьовден на мечките', 'Сретение Господне - в народната традиция мечките се събуждат на този ден. Затова се нарича Гергьовден на мечките.', 'На Гергьовден на мечките - мечките се събуждат.', 'tradition'),
('02-10', 2, 'Св. Харалампий', 'На Харалампиевден се празнува срещу болести и чуми. Св. Харалампий се смята за покровител срещу чумата.', 'Свети Харалампий - от чума пази, от болести брани.', 'tradition'),
('02-14', 2, 'Трифон Зарезан', 'Денят на винарите и лозарите. На този ден се рязват лозята и се полива с вино за берекет.', 'На Трифон Зарезан - рязай лозето, пей и весели се.', 'tradition'),
('03-01', 3, 'Баба Марта - Мартеници', 'На 1 март се подаряват мартеници - червено-бели усукани конци. Носят се докато се види щъркел или цъфнало дърво.', 'Март катурат - и калта хубост носят.', 'tradition'),
('03-03', 3, 'Освобождението', 'На 3 март България чества Освобождението от османско владичество. Ден на националната гордост.', 'Свободата е по-скъпа от злато.', 'tradition'),
('03-09', 3, 'Свети 40 мъченици - Летен Тодоровден', 'На този ден се правят огньове и се прескачат за здраве. Смята се, че на 40 мъченици зимата свършва.', 'На 40 мъченици - мечката излиза от дупката.', 'tradition'),
('03-25', 3, 'Благовещение', 'На Благовещение не се работи - който работи, ще го сполети беда. Смята се за ден на пролетта.', 'На Благовещение - не копай, не орай, не бери.', 'tradition'),
('04-23', 4, 'Гергьовден - Коляне на агнето', 'На Гергьовден се коли агне. Домакинята украсява дома с зеленина. Традиционно е да се яде агнешко и да се пие вино.', 'На Гергьовден - агне, на Илинден - ярец.', 'tradition'),
('05-06', 5, 'Гергьовден - Ден на храбростта', 'Гергьовден е и Ден на храбростта и Българската армия. Празник на пролетта, здравето и победата.', 'Гергьовден - пролетта е в разцвет.', 'tradition'),
('05-21', 5, 'Константин и Елена - Огнен празник', 'На този ден се палят огньове и се прескачат за здраве. Смята се за празник на слънцето и огъня.', 'На Константиновден - огънят лекува.', 'tradition'),
('05-24', 5, 'Ден на буквите', 'На 24 май се честват Светите братя Кирил и Методий, българската азбука, просвета и култура.', 'Българо, знайно ти е - писмеността ти е свещена.', 'tradition'),
('06-02', 6, 'Ботев ден', 'На 2 юни се чества смъртта на Христо Ботев и на всички загинали за свободата на България.', 'О, мийте се, синове на Балкана!', 'tradition'),
('06-24', 6, 'Еньовден - Билките', 'На Еньовден преди изгрев слънце момичетата берат билки, които се смятат за най-лековити. Прескачат огън за здраве.', 'Еньовите билки - на болен здраве дават.', 'tradition'),
('06-29', 6, 'Петровден - Летен празник', 'На Петровден се празнува в чест на Св. Петър и Павел. Традиционно се коли курбан и се прави голяма трапеза.', 'На Петровден - курбан за здраве.', 'tradition'),
('07-20', 7, 'Илинден - Празник на слънцето', 'На Илинден се празнува в чест на Св. пророк Илия. Смята се, че на този ден слънцето се завърта два пъти.', 'На Илинден - слънцето се завърта.', 'tradition'),
('08-06', 8, 'Преображение - Гроздобер', 'На Преображение се благославят първите гроздове. Смята се, че от този ден гроздето е узряло за ядене.', 'На Преображение - първото грозде се благославя.', 'tradition'),
('08-15', 8, 'Голяма Богородица - Курбан', 'На Голяма Богородица се коли курбан за здраве. Това е един от най-големите летни празници в България.', 'На Голяма Богородица - курбан за здраве и берекет.', 'tradition'),
('09-08', 9, 'Малка Богородица', 'На Малка Богородица се празнува рождението на Дева Мария. Традиционно се прави курбан и се раздава за здраве.', 'На Малка Богородица - дялове за здраве.', 'tradition'),
('09-14', 9, 'Кръстовден - Край на жътвата', 'На Кръстовден се празнува Въздвижение на Честния Кръст. Смята се, че на този ден жътвата трябва да е свършена.', 'На Кръстовден - жътвата свършва, есента започва.', 'tradition'),
('10-14', 10, 'Петковден - Есенен празник', 'На Петковден се празнува в чест на Св. Петка Търновска. Традиционно се коли курбан и се прави голяма трапеза.', 'На Петковден - курбан за здраве и берекет.', 'tradition'),
('10-26', 10, 'Димитровден - Зимски празник', 'На Димитровден се празнува в чест на Св. Димитър. Смята се, че на този ден зимата започва.', 'На Димитровден - зимата започва, лятото свършва.', 'tradition'),
('11-08', 11, 'Архангеловден - Мъжки празник', 'На Архангеловден се празнува в чест на Св. Архангел Михаил. Традиционно се коли курбан и се прави трапеза.', 'На Архангеловден - курбан за здраве.', 'tradition'),
('11-21', 11, 'Въведение Богородично', 'На Въведение Богородично се празнува въвеждането на Дева Мария в храма. Смята се за начало на зимните празници.', 'На Въведение - зимата е дошла.', 'tradition'),
('12-06', 12, 'Никулден - Рибен празник', 'На Никулден се празнува в чест на Св. Николай Мирликийски, покровител на моряците. Традиционно се яде риба.', 'На Никулден - риба на трапезата.', 'tradition'),
('12-24', 12, 'Бъдни вечер - Постна трапеза', 'Вечерята на Бъдни вечер е постна и съдържа нечетен брой ястия. На трапезата задължително има питка с пари и кравайче.', 'Колкото звезди на небето, толкова берекет на нивата.', 'tradition'),
('12-25', 12, 'Коледа - Коледари', 'Коледарите ходят по домовете и пеят коледни песни срещу подаръци. Обичаят е запазен в много български села.', 'Коледа дойде, берекет донесе.', 'tradition'),
('12-27', 12, 'Стефановден - Последен празник', 'На Стефановден се празнува в чест на Св. първомъченик Стефан. Смята се за последния голям празник за годината.', 'На Стефановден - годината се завършва.', 'tradition'),
(NULL, 1, 'Зимни обичаи', 'През зимата народът извършва различни обреди за прогонване на злите сили и привличане на здраве и берекет.', 'Зимата е за почивка, лятото - за работа.', 'custom'),
(NULL, 4, 'Пролетни обичаи', 'С настъпването на пролетта народът извършва различни обреди за плодородие, здраве и прогонване на злото.', 'Пролетта е майката на годината.', 'custom'),
(NULL, 7, 'Летни обичаи', 'През лятото се извършват обреди за предпазване от суша и градушки, за берекет и здраве.', 'Лятото е за жътва, есента - за сеитба.', 'custom'),
(NULL, 10, 'Есенни обичаи', 'През есента народът извършва обреди за благодарност за берекета и подготовка за зимата.', 'Есента е за жътва, зимата - за почивка.', 'custom')
